"use client";

import { useEffect, useMemo, useState } from "react";
import type { Locale } from "@/data/invitation";
import { invitationContent } from "@/data/invitation";

type CountdownParts = {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
};

function getCountdownParts(targetDate: Date): CountdownParts {
  const difference = Math.max(targetDate.getTime() - Date.now(), 0);
  const totalSeconds = Math.floor(difference / 1000);
  const days = Math.floor(totalSeconds / 86400);
  const hours = Math.floor((totalSeconds % 86400) / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  return { days, hours, minutes, seconds };
}

interface CountdownCardProps {
  locale: Locale;
}

export function CountdownCard({ locale }: CountdownCardProps) {
  const content = invitationContent[locale];
  const targetDate = useMemo(() => new Date("2026-08-24T16:00:00"), []);
  const [countdown, setCountdown] = useState<CountdownParts>(() => getCountdownParts(targetDate));

  useEffect(() => {
    const interval = window.setInterval(() => {
      setCountdown(getCountdownParts(targetDate));
    }, 1000);

    return () => window.clearInterval(interval);
  }, [targetDate]);

  const items = [
    { label: content.countdown.days, value: countdown.days },
    { label: content.countdown.hours, value: countdown.hours },
    { label: content.countdown.minutes, value: countdown.minutes },
    { label: content.countdown.seconds, value: countdown.seconds }
  ];

  return (
    <div className="rounded-3xl bg-sky-50/90 p-4 text-center shadow-sm shadow-sky-100/50 transition duration-300 hover:-translate-y-1 hover:shadow-lg hover:shadow-sky-100">
      <p className="text-xs font-semibold uppercase tracking-[0.3em] text-sky-700">{content.countdown.title}</p>
      <p className="mt-1 text-[0.7rem] font-medium uppercase tracking-[0.3em] text-slate-500">
        {content.countdown.subtitle}
      </p>
      <div className="mt-3 grid grid-cols-4 gap-2">
        {items.map((item) => (
          <div key={item.label} className="rounded-2xl bg-white/85 p-2 shadow-sm">
            <p className="text-lg font-black text-slate-900">{String(item.value).padStart(2, "0")}</p>
            <p className="text-[0.62rem] font-semibold uppercase tracking-[0.25em] text-sky-700">{item.label}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
