"use client";

import { Music2, Pause, Play } from "lucide-react";
import { useBackgroundMusic } from "@/hooks/use-background-music";

interface MusicDockProps {
  title: string;
  description: string;
}

export function MusicDock({ title, description }: MusicDockProps) {
  const { isPlaying, play, stop } = useBackgroundMusic();

  return (
    <div className="fixed bottom-4 right-4 z-50 sm:bottom-6 sm:right-6">
      <button
        type="button"
        onClick={isPlaying ? stop : play}
        className={`group flex h-14 w-14 items-center justify-center rounded-full border border-white/80 bg-white/92 shadow-[0_18px_45px_rgba(59,130,246,0.22)] backdrop-blur-xl transition hover:-translate-y-0.5 hover:shadow-[0_24px_60px_rgba(59,130,246,0.3)] ${isPlaying ? "ring-2 ring-sky-300" : ""}`}
        aria-label={isPlaying ? "Pausar música" : "Reproducir música"}
      >
        <span className={`flex h-10 w-10 items-center justify-center rounded-full transition ${isPlaying ? "bg-sky-700 text-white" : "bg-sky-100 text-sky-700 group-hover:bg-sky-200"}`}>
          {isPlaying ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5 translate-x-[1px]" />}
        </span>
        <span className="sr-only">
          {title}: {description}
        </span>
        <Music2 className="hidden" />
      </button>
    </div>
  );
}
