"use client";

import { useMemo, useState } from "react";
import type { Locale } from "@/data/invitation";
import { invitationContent } from "@/data/invitation";
import { SectionCard } from "@/components/ui/section-card";
import { buildWhatsAppLink } from "@/lib/whatsapp";
import { MessageCircleMore, PhoneCall } from "lucide-react";

interface RSVPSectionProps {
  locale: Locale;
}

const guestOptions = [1, 2, 3, 4, 5, 6, 7, 8];

export function RSVPSection({ locale }: RSVPSectionProps) {
  const content = invitationContent[locale];
  const [familyName, setFamilyName] = useState("");
  const [guestCount, setGuestCount] = useState("2");

  const whatsappMessage = useMemo(() => {
    const attendees = Number(guestCount) || 1;
    const displayName = familyName.trim() || content.rsvp.defaultFamily;

    return locale === "es"
      ? `Hola, confirmo mi asistencia al baby shower de Santiago.\n\nNombre o familia: ${displayName}\nNúmero de personas: ${attendees}`
      : `Hi, I'm confirming my attendance to Santiago's baby shower.\n\nName or family: ${displayName}\nNumber of guests: ${attendees}`;
  }, [content.rsvp.defaultFamily, familyName, guestCount, locale]);

  const whatsappLink = buildWhatsAppLink(content.rsvp.phone, whatsappMessage);

  return (
    <SectionCard title={content.rsvp.title}>
      <div className="grid gap-5 lg:grid-cols-[1.05fr_0.95fr]">
        <div className="rounded-[1.75rem] border border-sky-100 bg-[linear-gradient(135deg,rgba(239,246,255,0.95)_0%,rgba(255,255,255,0.98)_55%,rgba(224,242,254,0.95)_100%)] p-6 shadow-[0_20px_60px_rgba(56,189,248,0.08)]">
          <p className="text-xs font-semibold uppercase tracking-[0.35em] text-sky-700">{content.rsvp.heading}</p>
          <p className="mt-3 max-w-xl text-sm leading-7 text-slate-600">{content.rsvp.description}</p>
          <div className="mt-6 grid gap-4 md:grid-cols-2">
            <label className="space-y-2">
              <span className="text-xs font-semibold uppercase tracking-[0.3em] text-sky-700">{content.rsvp.familyLabel}</span>
              <input
                type="text"
                value={familyName}
                onChange={(event) => setFamilyName(event.target.value)}
                placeholder={content.rsvp.familyPlaceholder}
                className="w-full rounded-2xl border border-sky-100 bg-white px-4 py-3 text-sm text-slate-800 outline-none transition placeholder:text-slate-400 focus:border-sky-300 focus:ring-4 focus:ring-sky-100"
              />
            </label>
            <label className="space-y-2">
              <span className="text-xs font-semibold uppercase tracking-[0.3em] text-sky-700">{content.rsvp.peopleLabel}</span>
              <select
                value={guestCount}
                onChange={(event) => setGuestCount(event.target.value)}
                className="w-full rounded-2xl border border-sky-100 bg-white px-4 py-3 text-sm text-slate-800 outline-none transition focus:border-sky-300 focus:ring-4 focus:ring-sky-100"
              >
                <option value="">{content.rsvp.peoplePlaceholder}</option>
                {guestOptions.map((option) => (
                  <option key={option} value={option}>
                    {option}
                  </option>
                ))}
              </select>
            </label>
          </div>
          <div className="mt-6 flex flex-wrap gap-3">
            <a
              href={whatsappLink}
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center justify-center gap-2 rounded-full bg-sky-700 px-6 py-3 font-semibold text-white transition hover:-translate-y-0.5 hover:bg-sky-800"
            >
              <MessageCircleMore className="h-5 w-5" />
              {content.rsvp.submit}
            </a>
            <div className="inline-flex items-center gap-2 rounded-full border border-sky-200 bg-white px-5 py-3 text-sm font-semibold text-slate-700">
              <PhoneCall className="h-4 w-4 text-sky-700" />
              {content.rsvp.phone}
            </div>
          </div>
        </div>
        <div className="rounded-[1.75rem] border border-white/80 bg-white/90 p-5 shadow-[0_20px_60px_rgba(56,189,248,0.1)]">
          <div className="flex h-full min-h-[240px] items-center justify-center rounded-[1.35rem] border border-dashed border-sky-200 bg-gradient-to-br from-sky-50 via-white to-white p-6 text-center">
            <div className="max-w-xs">
              <p className="text-xs font-semibold uppercase tracking-[0.35em] text-sky-700">
                {locale === "es" ? "Vista previa" : "Preview"}
              </p>
              <p className="mt-3 text-xl font-bold text-slate-900">
                {familyName.trim() || content.rsvp.defaultFamily}
              </p>
              <p className="mt-2 text-sm leading-6 text-slate-600">
                {locale === "es"
                  ? `Asistirán ${guestCount || 1} personas.`
                  : `${guestCount || 1} guests will attend.`}
              </p>
              <p className="mt-5 text-sm leading-6 text-slate-500">
                {locale === "es"
                  ? "El mensaje de WhatsApp se completará con los datos que escribas para facilitar la confirmación."
                  : "The WhatsApp message will be completed with the details you enter to make confirmation easier."}
              </p>
            </div>
          </div>
        </div>
      </div>
    </SectionCard>
  );
}
