import type { Locale } from "@/data/invitation";
import { invitationContent } from "@/data/invitation";
import { SectionCard } from "@/components/ui/section-card";

interface PhraseSectionProps {
  locale: Locale;
}

export function PhraseSection({ locale }: PhraseSectionProps) {
  const content = invitationContent[locale];

  return (
    <SectionCard title={locale === "es" ? "Frase especial" : "Special quote"}>
      <p className="text-lg leading-8 text-slate-700 md:text-xl">{content.phrase}</p>
    </SectionCard>
  );
}
